import React from 'react';
import './About.css';

const About = () => {
  const skills = [
    { category: 'Frontend', items: ['React', 'JavaScript', 'HTML5', 'CSS3'] },
    { category: 'Backend', items: ['Node.js', 'Python', 'SQL', 'MongoDB'] },
    { category: 'Tools', items: ['Git', 'Docker', 'AWS', 'VS Code'] },
    { category: 'Other', items: ['REST APIs', 'Agile', 'UI/UX', 'Testing'] }
  ];

  return (
    <section className="about section">
      <div className="container">
        <h2 className="section-title">About Me</h2>
        <div className="about-content">
          <div className="about-text">
            <p>
              I am a passionate Full Stack Developer with a strong foundation in web development
              and a keen eye for creating elegant solutions to complex problems. With several
              years of experience in building web applications, I specialize in creating
              responsive, user-friendly interfaces and robust backend systems.
            </p>
            <p>
              My journey in software development began with a curiosity for how things work on
              the internet. This curiosity led me to pursue a career in web development, where
              I've had the opportunity to work on various projects ranging from small business
              websites to large-scale enterprise applications.
            </p>
            <p>
              I believe in writing clean, maintainable code and following best practices to
              ensure the highest quality of work. I'm always eager to learn new technologies
              and stay up-to-date with the latest trends in web development.
            </p>
          </div>
          <div className="skills-grid">
            {skills.map((skillGroup, index) => (
              <div key={index} className="skill-category">
                <h3 className="skill-category-title">{skillGroup.category}</h3>
                <ul className="skill-list">
                  {skillGroup.items.map((skill, skillIndex) => (
                    <li key={skillIndex} className="skill-item">
                      {skill}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;
